// std::vector<std::string>::~vector()
//
// Destroys each std::string element in [begin, end), then frees the
// underlying storage via operator delete (the tail-call to 0x1260).
// Each std::string has the libstdc++ SSO layout: { char* _M_dataplus;
// size_t _M_string_length; union { char _M_local_buf[16]; size_t _M_allocated_capacity; }; }
// so sizeof(std::string) == 32 and the inline-buffer pointer is at offset +16.
void std__vector_string__dtor(void *this)
{
    struct string {
        char   *dataplus;        // +0
        size_t  length;          // +8
        char   *local_buf_or_cap;// +16  (points at &local_buf[0] when SSO)
        char    local_buf[8];    // +24
    };
    struct vector {
        struct string *begin;       // +0  _M_start
        struct string *end;         // +8  _M_finish
        struct string *cap_end;     // +16 _M_end_of_storage
    };

    struct vector *v   = (struct vector *)this;
    struct string *end = v->end;
    struct string *p   = v->begin;

    /* Destroy each element: if the string is not in SSO mode, free its heap buffer. */
    for (; p != end; ++p) {
        if (p->dataplus != (char *)&p->local_buf_or_cap) {
            operator_delete(p->dataplus);   /* call 0x1260 == operator delete */
        }
    }

    /* Free the vector's element storage. */
    struct string *storage = v->begin;
    if (storage != NULL) {
        size_t bytes = (size_t)((char *)v->cap_end - (char *)storage);
        operator_delete(storage, bytes);    /* sized operator delete, tail call */
    }
}

